sql:
SELECT team_member_name, role, department
FROM team_members
WHERE team_member_id = 1234;

SELECT p.client_id, tm.team_member_name
FROM projects p
JOIN team_members tm ON p.project_manager_id = tm.team_member_id;

SELECT department, COUNT(team_member_id) AS team_member_count
FROM team_members
GROUP BY department;

SELECT AVG(strftime('%Y', 'now') - strftime('%Y', f.feedback_date)) AS average_age
FROM team_members tm
JOIN feedbacks f ON tm.team_member_id = f.team_member_id;

